function solve(nums: number[]): number {
    const n = nums.length;
    const MAX_VAL = 1000000;

    const spf = new Array(MAX_VAL + 1);
    for (let i = 0; i <= MAX_VAL; i++) {
        spf[i] = i;
    }
    for (let i = 2; i * i <= MAX_VAL; i++) {
        if (spf[i] === i) {
            for (let j = i * i; j <= MAX_VAL; j += i) {
                if (spf[j] === j) {
                    spf[j] = i;
                }
            }
        }
    }

    const primesAppeared = new Set<number>();
    for (const num of nums) {
        if (num < 2) continue;
        if (spf[num] === num) {
            primesAppeared.add(num);
        }
    }

    const primeToIndices = new Map<number, number[]>();
    primesAppeared.forEach(p => {
        primeToIndices.set(p, []);
    });

    for (let j = 0; j < n; j++) {
        const num = nums[j];
        if (num === 1) continue;
        let temp = num;
        const factors = new Set<number>();
        while (temp > 1) {
            const p = spf[temp];
            factors.add(p);
            while (temp % p === 0) {
                temp = Math.floor(temp / p);
            }
        }
        for (const p of factors) {
            if (primesAppeared.has(p)) {
                primeToIndices.get(p)?.push(j);
            }
        }
    }

    const dist = new Array(n).fill(-1);
    const queue: number[] = [];
    dist[0] = 0;
    queue.push(0);
    const usedPrimes = new Set<number>();

    while (queue.length > 0) {
        const i = queue.shift()!;
        const steps = dist[i];
        if (i === n - 1) {
            return steps;
        }

        const neighbors = [i - 1, i + 1];
        for (const neighbor of neighbors) {
            if (neighbor >= 0 && neighbor < n && dist[neighbor] === -1) {
                dist[neighbor] = steps + 1;
                queue.push(neighbor);
            }
        }

        const val = nums[i];
        if (primesAppeared.has(val)) {
            const p = val;
            if (usedPrimes.has(p)) {
                continue;
            }
            usedPrimes.add(p);
            const list = primeToIndices.get(p);
            if (!list) continue;
            for (const j of list) {
                if (j === i) continue;
                if (dist[j] === -1) {
                    dist[j] = steps + 1;
                    queue.push(j);
                }
            }
        }
    }

    return dist[n - 1];
}
```

