    dist[0] = 0;
    q.push(0);
    const usedPrimes = new Set<number>();

    while (head < q.length) {
        const i = q[head];
        head++;
        if (i === n - 1) break;

        for (const neighbor of [i + 1, i - 1]) {
            if (neighbor >= 0 && neighbor < n && dist[neighbor] === -1) {
